const express = require('express');
const redis = require('redis');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('error', (err) => console.error('Redis Client Error', err));

(async () => {
  await redisClient.connect();
  console.log('Connected to Redis');
})();

// Validate and sanitize search patterns to prevent injection
// Only allow alphanumeric characters, *, ?, [, ], -, _, :, .
function sanitizePattern(pattern) {
  if (typeof pattern !== 'string') {
    return null;
  }
  // Allow only safe glob-style pattern characters
  // Alphanumeric, *, ?, [, ], -, _, :, . are legitimate for Redis key patterns
  const safePatternRegex = /^[a-zA-Z0-9*?\[\]\-_:.\s]+$/;
  if (!safePatternRegex.test(pattern)) {
    return null;
  }
  // Prevent excessively broad patterns that could cause performance issues
  if (pattern.length > 256) {
    return null;
  }
  return pattern;
}

