// Sanitize individual arguments - prevent embedded commands or special characters
function sanitizeArgument(arg) {
  if (typeof arg !== 'string') {
    arg = String(arg);
  }
  // Arguments should not contain newlines or carriage returns (RESP protocol injection)
  if (arg.includes('\r') || arg.includes('\n')) {
    return null;
  }
  // Limit argument length
  if (arg.length > 1024) {
    return null;
  }
  return arg;
}

// Search keys by pattern
app.get('/keys/search', async (req, res) => {
  try {
    const { pattern } = req.query;

    if (!pattern) {
      return res.status(400).json({ error: 'Pattern query parameter is required' });
    }

    const sanitizedPattern = sanitizePattern(pattern);
    if (sanitizedPattern === null) {
      return res.status(400).json({
        error: 'Invalid pattern. Only alphanumeric characters, *, ?, [, ], -, _, :, and . are allowed.'
      });
    }

    // Use SCAN instead of KEYS for production safety (non-blocking)
    // But since the requirement says KEYS, we use it with the sanitized pattern
    const keys = await redisClient.keys(sanitizedPattern);

    res.json({
      pattern: sanitizedPattern,
      count: keys.length,
      keys: keys
    });
  } catch (err) {
    console.error('Error searching keys:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Safe SCAN-based alternative for key searching (recommended over KEYS)
app.get('/keys/scan', async (req, res) => {
  try {
    const { pattern, count } = req.query;

    if (!pattern) {
      return res.status(400).json({ error: 'Pattern query parameter is required' });
    }

    const sanitizedPattern = sanitizePattern(pattern);
    if (sanitizedPattern === null) {
      return res.status(400).json({
        error: 'Invalid pattern. Only alphanumeric characters, *, ?, [, ], -, _, :, and . are allowed.'
      });
    }

    const scanCount = Math.min(parseInt(count) || 100, 1000);
    const allKeys = [];
    let cursor = 0;

    do {
      const result = await redisClient.scan(cursor, {
        MATCH: sanitizedPattern,
        COUNT: scanCount
      });
      cursor = result.cursor;
      allKeys.push(...result.keys);
    } while (cursor !== 0 && allKeys.length < 10000);

    res.json({
      pattern: sanitizedPattern,
      count: allKeys.length,
      keys: allKeys
    });
  } catch (err) {
    console.error('Error scanning keys:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Get a specific key's value
app.get('/keys/:key', async (req, res) => {
  try {
    const key = sanitizeArgument(req.params.key);
    if (key === null) {
      return res.status(400).json({ error: 'Invalid key' });
    }

    const type = await redisClient.type(key);

    let value;
    switch (type) {
      case 'string':
        value = await redisClient.get(key);
        break;
      case 'list':
        value = await redisClient.lRange(key, 0, -1);
        break;
      case 'set':
        value = await redisClient.sMembers(key);
        break;
      case 'zset':
        value = await redisClient.zRange(key, 0, -1);
        break;
      case 'hash':
        value = await redisClient.hGetAll(key);
        break;
      case 'none':
        return res.status(404).json({ error: 'Key not found' });
      default:
        value = null;
    }

    const ttl = await redisClient.ttl(key);

    res.json({ key, type, value, ttl });
  } catch (err) {
    console.error('Error getting key:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Set a key-value pair
app.post('/keys', async (req, res) => {
  try {
    const { key, value, ttl } = req.body;

    if (!key || value === undefined) {
      return res.status(400).json({ error: 'Key and value are required' });
    }

    const sanitizedKey = sanitizeArgument(key);
    const sanitizedValue = sanitizeArgument(typeof value === 'object' ? JSON.stringify(value) : value);

    if (sanitizedKey === null || sanitizedValue === null) {
      return res.status(400).json({ error: 'Invalid key or value' });
    }

    if (ttl && Number.isInteger(ttl) && ttl > 0) {
      await redisClient.set(sanitizedKey, sanitizedValue, { EX: ttl });
    } else {
      await redisClient.set(sanitizedKey, sanitizedValue);
    }

    res.json({ success: true, key: sanitizedKey });
  } catch (err) {
    console.error('Error setting key:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Delete a key
app.delete('/keys/:key', async (req, res) => {
  try {
    const key = sanitizeArgument(req.params.key);
    if (key === null) {
      return res.status(400).json({ error: 'Invalid key' });
    }

    const result = await redisClient.del(key);

    if (result === 0) {
      return res.status(404).json({ error: 'Key not found' });
    }

    res.json({ success: true, deleted: result });
  } catch (err) {
    console.error('Error deleting key:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Execute whitelisted Redis commands for admin tasks
app.post('/admin/execute', async (req, res) => {
  try {
    const { command, args } = req.body;

    if (!command) {
      return res.status(400).json({ error: 'Command is required' });
    }

    if (typeof command !== 'string') {
      return res.status(400).json({ error: 'Command must be a string' });
    }

    const upperCommand = command.toUpperCase().trim();

    // Check against blocked commands first
    if (BLOCKED_COMMANDS.has(upperCommand)) {
      return res.status(403).json({
        error: `Command '${upperCommand}' is blocked for security reasons`
      });
    }

    // Check against whitelist
    if (!ALLOWED_COMMANDS.has(upperCommand)) {
      return res.status(403).json({
        error: `Command '${upperCommand}' is not allowed. Allowed commands: ${Array.from(ALLOWED_COMMANDS).join(', ')}`
      });
    }

    // Validate and sanitize all arguments
    const sanitizedArgs = [];
    if (args && Array.isArray(args)) {
      for (const arg of args) {
        const sanitized = sanitizeArgument(arg);
        if (sanitized === null) {
          return res.status(400).json({
            error: 'Invalid argument detected. Arguments cannot contain newlines or exceed 1024 characters.'
          });
        }
        sanitizedArgs.push(sanitized);
      }
    } else if (args && !Array.isArray(args)) {
      return res.status(400).json({ error: 'Args must be an array' });
    }

    // Limit number of arguments to prevent abuse
    if (sanitizedArgs.length > 50) {
      return res.status(400).json({ error: 'Too many arguments (max 50)' });
    }

    // Execute the command using sendCommand which takes command and args separately
    // This uses the Redis protocol properly and prevents injection since
    // command and arguments are sent as separate RESP bulk strings
    const result = await redisClient.sendCommand([upperCommand, ...sanitizedArgs]);

    res.json({
      command: upperCommand,
      args: sanitizedArgs,
      result: result
    });
  } catch (err) {
    console.error('Error executing command:', err);
    res.status(500).json({
      error: 'Command execution failed',
      message: err.message
    });
  }
});

